// AUTO-GENERATED DRAFT SCREEN: CryptoUnstakingScreen
import React, { useState, useCallback, useMemo } from 'react';
import { Button } from '@/components/ui/button';
import { Input } from '@/components/ui/input';
import { Card, CardContent, CardHeader, CardTitle, CardDescription } from '@/components/ui/card';
import { Label } from '@/components/ui/label';
import { Alert, AlertDescription, AlertTitle } from '@/components/ui/alert';
import { Loader2 } from 'lucide-react'; // For loading spinner

// Placeholder for tRPC hooks - In a real application, these would be generated by tRPC
// For this task, we'll simulate their behavior.
interface UseStakedBalanceQueryResult {
  data: { amount: number } | undefined;
  isLoading: boolean;
  error: Error | null;
}

interface UseUnstakeMutationResult {
  mutate: (variables: { amount: number }) => Promise<void>;
  isLoading: boolean;
  error: Error | null;
  isSuccess: boolean;
}

const useStakedBalanceQuery = (): UseStakedBalanceQueryResult => {
  const [data, setData] = useState<{ amount: number } | undefined>(undefined);
  const [isLoading, setIsLoading] = useState(true);
  const [error, setError] = useState<Error | null>(null);

  React.useEffect(() => {
    const timer = setTimeout(() => {
      // Simulate fetching data
      setData({ amount: 1000.50 }); // Example staked amount
      setIsLoading(false);
    }, 1500);
    return () => clearTimeout(timer);
  }, []);

  return { data, isLoading, error };
};

const useUnstakeMutation = (): UseUnstakeMutationResult => {
  const [isLoading, setIsLoading] = useState(false);
  const [error, setError] = useState<Error | null>(null);
  const [isSuccess, setIsSuccess] = useState(false);

  const mutate = useCallback(async (variables: { amount: number }) => {
    setIsLoading(true);
    setError(null);
    setIsSuccess(false);
    try {
      await new Promise(resolve => setTimeout(resolve, 2000)); // Simulate API call
      if (variables.amount > 500) {
        throw new Error('Cannot unstake more than 500 at a time.');
      }
      setIsSuccess(true);
    } catch (err: any) {
      setError(err);
    }
    setIsLoading(false);
  }, []);

  return { mutate, isLoading, error, isSuccess };
};

interface UnstakingFormState {
  amount: string;
}

const CryptoUnstakingScreen: React.FC = () => {
  const [formState, setFormState] = useState<UnstakingFormState>({ amount: '' });
  const [localError, setLocalError] = useState<string | null>(null);

  const { data: stakedBalance, isLoading: isLoadingBalance, error: balanceError } = useStakedBalanceQuery();
  const { mutate: unstake, isLoading: isUnstaking, error: unstakeError, isSuccess: unstakeSuccess } = useUnstakeMutation();

  const isLoading = isLoadingBalance || isUnstaking;
  const hasError = localError || balanceError || unstakeError;

  const handleAmountChange = useCallback((e: React.ChangeEvent<HTMLInputElement>) => {
    setFormState({ ...formState, amount: e.target.value });
    setLocalError(null);
  }, [formState]);

  const handleSubmit = useCallback(async (e: React.FormEvent) => {
    e.preventDefault();
    setLocalError(null);

    const amountToUnstake = parseFloat(formState.amount);

    if (isNaN(amountToUnstake) || amountToUnstake <= 0) {
      setLocalError('Please enter a valid positive amount to unstake.');
      return;
    }

    if (stakedBalance && amountToUnstake > stakedBalance.amount) {
      setLocalError('Amount exceeds your staked balance.');
      return;
    }

    await unstake({ amount: amountToUnstake });
    if (unstakeSuccess) {
      setFormState({ amount: '' }); // Clear form on success
    }
  }, [formState.amount, stakedBalance, unstake, unstakeSuccess]);

  const displayError = useMemo(() => {
    if (localError) return localError;
    if (balanceError) return `Failed to load balance: ${balanceError.message}`;
    if (unstakeError) return `Unstaking failed: ${unstakeError.message}`;
    return null;
  }, [localError, balanceError, unstakeError]);

  return (
    <div className="min-h-screen bg-background flex items-center justify-center p-4 dark:bg-gray-950">
      <Card className="w-full max-w-md shadow-lg dark:bg-gray-900 dark:text-gray-50">
        <CardHeader>
          <CardTitle className="text-3xl font-bold text-center">Crypto Unstaking</CardTitle>
          <CardDescription className="text-center text-gray-500 dark:text-gray-400">
            Unstake your assets from the platform.
          </CardDescription>
        </CardHeader>
        <CardContent className="space-y-6">
          {isLoadingBalance ? (
            <div className="flex flex-col items-center justify-center space-y-2">
              <Loader2 className="h-8 w-8 animate-spin text-primary" aria-label="Loading staked balance" />
              <p className="text-sm text-gray-500 dark:text-gray-400">Loading staked balance...</p>
            </div>
          ) : (
            <div className="text-center text-lg font-medium dark:text-gray-200" aria-live="polite">
              Current Staked Balance: {stakedBalance?.amount.toFixed(2) || 'N/A'} SKY
            </div>
          )}

          {displayError && (
            <Alert variant="destructive" aria-live="assertive">
              <AlertTitle>Error</AlertTitle>
              <AlertDescription>{displayError}</AlertDescription>
            </Alert>
          )}

          {unstakeSuccess && !isUnstaking && (
            <Alert className="bg-green-500 text-white" aria-live="polite">
              <AlertTitle>Success!</AlertTitle>
              <AlertDescription>Your assets have been successfully unstaked.</AlertDescription>
            </Alert>
          )}

          <form onSubmit={handleSubmit} className="space-y-4">
            <div className="grid gap-2">
              <Label htmlFor="amount" className="text-base">Amount to Unstake</Label>
              <Input
                id="amount"
                type="number"
                placeholder="0.00"
                value={formState.amount}
                onChange={handleAmountChange}
                required
                min="0"
                step="any"
                disabled={isLoading}
                aria-invalid={!!displayError}
                aria-describedby={displayError ? 'error-message' : undefined}
                className="dark:bg-gray-800 dark:text-gray-50 dark:border-gray-700"
              />
            </div>
            <Button
              type="submit"
              className="w-full text-lg py-2"
              disabled={isLoading || !formState.amount || parseFloat(formState.amount) <= 0}
              aria-label={isUnstaking ? 'Unstaking in progress' : 'Unstake assets'}
            >
              {isUnstaking ? (
                <>
                  <Loader2 className="mr-2 h-5 w-5 animate-spin" />
                  Unstaking...
                </>
              ) : (
                'Unstake'
              )}
            </Button>
          </form>
        </CardContent>
      </Card>
    </div>
  );
};

export default CryptoUnstakingScreen;
